description:
File: lichen/subsys/lichen/meshtastic/adapter.c:940-975

  static bool resolve_text_destination(
      struct lichen_meshtastic_adapter *adapter,
      struct lichen_meshtastic_adapter_packet_info *packet)
  {
      ...
      nodedb_peer_snapshot(adapter, info.node_num, &peers);
      ...
      for (size_t i = 0U; i < peers.emit_count; i++) {
          if (peers.node_nums[i] != packet->to) {
              continue;
          }
          memcpy(packet->to_eui64, peers.peers[i].eui64,
                 sizeof(packet->to_eui64));
          peer_eui64_to_iid(packet->to_eui64, packet->to_iid);
          packet->has_to_peer = true;
          return true;
      }
      return false;
  }

When the function returns false (destination not found), packet->has_to_peer is not explicitly set to false. It relies on memset in parse_packet initializing it to 0.

If parse_packet ever changes to not zero-initialize, or if packet_info is reused, has_to_peer could have stale data.

Consider explicitly setting packet->has_to_peer = false; at function start or in false return paths.
